import React from 'react';
import '/ParticleBackground.css';

const ParticleBackground = () => {
  return (
    <div className="particles-container">
      {/* Create as many particles as you want */}
      <div className="particle" style={{ top: '50%', left: '50%' }}></div>
      <div className="particle" style={{ top: '30%', left: '70%' }}></div>
      <div className="particle" style={{ top: '70%', left: '30%' }}></div>
      {/* Add more particles as desired */}
    </div>
  );
};

export default ParticleBackground;
